/**
 * Represents a duplicated file by file type errotr with all the informetion
 * it needs to flow correctly
 */
class DuplicatedFileByFileTypeError extends Error {
  constructor({ baseDir, previousFile, currentFile }) {
    super('Duplicated file by file type');

    /**
     * @type { string } - Directory path used to get duplicated files full path
     */
    this.baseDir = baseDir;
    /**
     * @type { string } - Relative path of the file set before the new file by file type
     */
    this.previousFile = previousFile;
    /**
     * @type { string } - Relative path of the new file
     */
    this.currentFile = currentFile;
  }
}

module.exports = {
  DuplicatedFileByFileTypeError,
};
